
const APP_KEY='SKYE_LOCAL_LEAD_SCRUBBER_V1';
let state=load(APP_KEY,{leads:[]});
const badWords=['bank','wells fargo','chase','franchise','franchis','university','hospital','corporate','llc - headquarters','headquarters','branch','campus'];
function parseLeadLine(line){
  const email = (line.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig)||[''])[0];
  const phone = (line.match(/(\+?1[-.\s]?)?(\(?\d{3}\)?[-.\s]?)\d{3}[-.\s]?\d{4}/)||[''])[0];
  const url = (line.match(/https?:\/\/\S+/i)||[''])[0];
  const parts = line.split('|').map(s=>s.trim()).filter(Boolean);
  const business = parts[0] || line.replace(email,'').replace(phone,'').replace(url,'').trim();
  const lower = line.toLowerCase();
  const flags = [];
  if(badWords.some(w=>lower.includes(w))) flags.push('exclude');
  if(!email) flags.push('no_email');
  if(!phone) flags.push('no_phone');
  if(/owner|founder|manager|director/.test(lower)) flags.push('dm_hint');
  const score = Math.max(5, 100 - (flags.includes('exclude')?65:0) - (flags.includes('no_email')?18:0) - (flags.includes('no_phone')?12:0) + (flags.includes('dm_hint')?18:0));
  return {
    id: uid('lead'),
    business_name: business.slice(0,120),
    business_email: email,
    phone,
    booking_link: url,
    notes: line,
    classification: flags.includes('exclude') ? 'Exclude' : score >= 82 ? 'Priority' : score >= 60 ? 'Review' : 'Low',
    score,
    flags
  };
}
function scrub(){
  const leads = lines($('#raw-leads').value).map(parseLeadLine).filter(l=>l.business_name);
  state.leads = dedupe(leads);
  store(APP_KEY,state);
  renderLeads();
}
function dedupe(leads){
  const seen = new Set();
  return leads.filter(lead => {
    const key = `${lead.business_name.toLowerCase()}|${lead.business_email.toLowerCase()}`;
    if(seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
function renderLeads(){
  $('#lead-table').innerHTML = state.leads.map(lead=>`
    <tr><td>${lead.business_name}</td><td>${lead.business_email || ''}</td><td>${lead.phone || ''}</td><td>${lead.classification}</td><td>${lead.score}</td></tr>`).join('');
  const flagged = state.leads.filter(l=>l.flags.length);
  $('#flag-cards').innerHTML = flagged.length ? flagged.map(lead=>`
    <div class="card"><div class="card-title">${lead.business_name}</div><div class="card-meta">${lead.flags.join(' · ')}</div><div class="small">${lead.notes}</div></div>`).join('') : '<div class="small">No flags</div>';
  const summary = [
    {label:'Total', value:state.leads.length},
    {label:'Priority', value:state.leads.filter(l=>l.classification==='Priority').length},
    {label:'Review', value:state.leads.filter(l=>l.classification==='Review').length},
    {label:'Exclude', value:state.leads.filter(l=>l.classification==='Exclude').length}
  ];
  $('#lead-summary').innerHTML = summary.map(k=>`<div class="kpi"><div class="v">${k.value}</div><div class="l">${k.label}</div></div>`).join('');
  $('#lead-preview').textContent = JSON.stringify(state.leads.slice(0,20), null, 2);
}
function buildAEFlowExport(){
  const now = new Date().toISOString();
  const ae = $('#ae-name').value.trim();
  const route = $('#ae-route').value.trim();
  const service = $('#ae-service').value.trim();
  const accepted = state.leads.filter(l=>l.classification!=='Exclude');
  return {
    app:'AE FLOW by Skyes Over London',
    version:'1.0',
    exported_at: now,
    settings:{depositPct:0.4, brand:{orgName:'Skyes Over London LC',replyEmail:'',tagline:'Proven operator network + conversion systems',handoffFooter:'Internal use. Generated by AE FLOW.'}},
    visits: accepted.map(l=>({
      id: uid('visit'),
      created_at: now,
      updated_at: now,
      date_key: now.slice(0,10),
      ae_name: ae,
      route,
      business_name: l.business_name,
      contact_name: '',
      business_email: l.business_email,
      phone: l.phone,
      service_1: service,
      service_area: '',
      lead_action: 'Form submissions',
      response_speed: 'Next day or later',
      lead_source: 'Walk-ins',
      booking_link: l.booking_link,
      permission: 'yes',
      status: 'New',
      follow_up_date: '',
      notes: l.notes,
      tags: []
    })),
    accounts: accepted.map(l=>({
      id: uid('account'),
      created_at: now,
      updated_at: now,
      ae_name: ae,
      route,
      business_name: l.business_name,
      business_email: l.business_email,
      phone: l.phone,
      contact_name: '',
      service_1: service,
      service_area: '',
      website_or_booking: l.booking_link,
      permission: 'yes',
      account_status: 'Active (Vetted)',
      notes: l.notes,
      tags:[]
    })),
    deals:[],
    handoff_log:[]
  };
}
$('#scrub-leads').addEventListener('click', scrub);
$('#load-sample-leads').addEventListener('click', ()=>{
  $('#raw-leads').value = `Copper Sky Capital | https://copperskycapital.com/ | site form\nLocal Shop Owner | owner@localshop.com | 602-555-1000 | https://localshop.com\nBig Bank Corporate Branch | info@bigbank.com | 480-222-9999`;
  scrub();
});
$('#export-ae-json').addEventListener('click', ()=> downloadJSON('ae-flow-import.json', buildAEFlowExport()));
$('#export-leads-csv').addEventListener('click', ()=> downloadText('local-leads.csv', rowsToCSV(state.leads), 'text/csv'));
$('#export-app').addEventListener('click', ()=> downloadJSON('local-lead-scrubber.json', state));
$('#import-app-trigger').addEventListener('click', ()=> $('#import-app').click());
$('#import-app').addEventListener('change', async e=>{ const f=e.target.files[0]; if(!f) return; state=await readJSONFile(f); store(APP_KEY,state); renderLeads(); });
$('#reset-app').addEventListener('click', ()=>{ if(confirm('Reset app state?')){ localStorage.removeItem(APP_KEY); state={leads:[]}; renderLeads(); $('#raw-leads').value=''; $('#lead-preview').textContent=''; }});
renderLeads();
